import json
import pymysql
import os

def lambda_handler(event, context):
    db_host = os.environ.get('DB_HOST')
    db_user = os.environ.get('DB_USER')
    db_password = os.environ.get('DB_PASSWORD')
    db_name = os.environ.get('DB_NAME')
    
    connection = None
    
    try:
        connection = pymysql.connect(
            host=db_host,
            user=db_user,
            password=db_password,
            database=db_name,
            charset='utf8mb4',
            cursorclass=pymysql.cursors.DictCursor
        )
        
        query_params = event.get('queryStringParameters', {}) or {}
        body_params = {}
        
        if event.get('body'):
            try:
                body_params = json.loads(event['body'])
            except:
                pass
        
        search_params = {**query_params, **body_params}
        
        query, values = build_search_query(search_params)
        
        with connection.cursor() as cursor:
            cursor.execute(query, values)
            results = cursor.fetchall()
        
        return {
            'statusCode': 200,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({
                'success': True,
                'count': len(results),
                'data': results
            })
        }
        
    except Exception as e:
        return {
            'statusCode': 500,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({
                'success': False,
                'error': str(e)
            })
        }
        
    finally:
        if connection:
            connection.close()


def build_search_query(params):
    base_query = "SELECT * FROM products WHERE 1=1"
    conditions = []
    values = []
    
    if params.get('id'):
        conditions.append("id = %s")
        values.append(params['id'])
    
    if params.get('name'):
        conditions.append("name LIKE %s")
        values.append(f"%{params['name']}%")
    
    if params.get('category'):
        conditions.append("category = %s")
        values.append(params['category'])
    
    if params.get('min_price'):
        conditions.append("price >= %s")
        values.append(float(params['min_price']))
    
    if params.get('max_price'):
        conditions.append("price <= %s")
        values.append(float(params['max_price']))
    
    if params.get('brand'):
        conditions.append("brand = %s")
        values.append(params['brand'])
    
    if params.get('in_stock'):
        if params['in_stock'].lower() in ['true', '1', 'yes']:
            conditions.append("stock_quantity > 0")
    
    if params.get('tags'):
        tags = params['tags'].split(',') if isinstance(params['tags'], str) else params['tags']
        tag_conditions = []
        for tag in tags:
            tag_conditions.append("tags LIKE %s")
            values.append(f"%{tag.strip()}%")
        if tag_conditions:
            conditions.append(f"({' OR '.join(tag_conditions)})")
    
    if params.get('description'):
        conditions.append("description LIKE %s")
        values.append(f"%{params['description']}%")
    
    if params.get('sku'):
        conditions.append("sku = %s")
        values.append(params['sku'])
    
    if params.get('status'):
        conditions.append("status = %s")
        values.append(params['status'])
    
    if params.get('created_after'):
        conditions.append("created_at >= %s")
        values.append(params['created_after'])
    
    if params.get('created_before'):
        conditions.append("created_at <= %s")
        values.append(params['created_before'])
    
    if conditions:
        base_query += " AND " + " AND ".join(conditions)
    
    order_by = params.get('order_by', 'id')
    order_direction = params.get('order_direction', 'ASC').upper()
    
    allowed_columns = ['id', 'name', 'price', 'created_at', 'updated_at', 'stock_quantity']
    if order_by in allowed_columns and order_direction in ['ASC', 'DESC']:
        base_query += f" ORDER BY {order_by} {order_direction}"
    
    limit = int(params.get('limit', 100))
    offset = int(params.get('offset', 0))
    
    if limit > 0:
        base_query += f" LIMIT {limit}"
    
    if offset > 0:
        base_query += f" OFFSET {offset}"
    
    return base_query, values